import { getServerSession } from "next-auth";
import { authOptions } from "../lib/auth";
import { redirect } from "next/navigation";

export default async function DashboardPage() {
  const session = await getServerSession(authOptions);
  if (!session) redirect("/login");

  return (
    <section className="container">
      <h1 style={{ marginBottom: '5px' }}>Dashboard สุขภาพของคุณ 📊</h1>
      <p className="muted" style={{ marginBottom: '30px' }}>วิเคราะห์ข้อมูลพฤติกรรมการทำงานของคุณ {session.user?.name}</p>

      <div className="grid">
        <article className="card" style={{ textAlign: 'center' }}>
          <h3 style={{ color: '#64748b' }}>อาการฮิตสัปดาห์นี้</h3>
          <p style={{ fontSize: '2rem', fontWeight: 'bold', color: '#ef4444' }}>ปวดหลัง</p>
          <p className="muted">พบอาการนี้ 4 วันซ้อน ระวังด้วยนะคะ!</p>
        </article>

        <article className="card" style={{ textAlign: 'center' }}>
          <h3 style={{ color: '#64748b' }}>การลุกยืดเส้นยืดสาย</h3>
          <p style={{ fontSize: '2rem', fontWeight: 'bold', color: '#10b981' }}>2 / 7 วัน</p>
          <p className="muted">พยายามตั้งนาฬิกาปลุกให้ลุกเดินบ่อยขึ้นนะคะ</p>
        </article>
      </div>
    </section>
  );
}